session_edges_anchor_by_kind.value:
(
        "session_edges"."kind" = 'derives' AND "session_edges"."anchor_id" IS NOT NULL
      ) OR (
        "session_edges"."kind" <> 'derives' AND "session_edges"."anchor_id" IS NULL
      )

runtime_compensations_resolution_check.value:
jsonb_typeof("runtime_compensations"."resolution_evidence") = 'object' AND (
        (
          "runtime_compensations"."status" = 'succeeded'
          AND "runtime_compensations"."resolved_at" IS NOT NULL
          AND "runtime_compensations"."resolution_evidence" <> '{}'::jsonb
        ) OR (
          "runtime_compensations"."status" <> 'succeeded'
          AND "runtime_compensations"."resolved_at" IS NULL
        )
      )
